                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        # Basic personal predicates
        if p == "birthdate":
            return f"{subj} was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "birthname":
            return f"{subj} was born as {obj}"
        if p == "deathdate":
            return f"{subj} died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            # Map common country names to demonyms
            demonyms = {
                "United States": "American",
                "USA": "American",
                "U.S.": "American",
                "Canada": "Canadian",
                "Russia": "Russian",
                "United Kingdom": "British",
                "France": "French",
                "Germany": "German",
            }
            demo = demonyms.get(obj, None)
            return f"{subj} was an {demo}" if demo else f"{subj} is from {obj}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return f"{subj} is retired"
            if low == "active":
                return f"{subj} is active"
            return f"{subj} has status {obj}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "dateretirement":
            return f"{subj} retired on {fmt_date(obj)}"
        if p == "almaMater".lower():
            return f"{subj} earned a degree from {obj}"
        if p == "mission":
            return f"{subj} served on the {obj} mission"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
